package com.example.deeplink

import android.app.Activity
import android.content.Context
import android.content.Intent
import android.net.Uri
import android.os.Bundle

class DeepLinkActivity : Activity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        DeepLinkHandler.handle(this, intent)
        finish()
    }
}

object DeepLinkHandler {

    private const val SCHEME = "myapp"

    fun handle(context: Context, intent: Intent?) {
        val uri = intent?.data
        if (uri == null || !isSupported(uri)) {
            launchMain(context)
            return
        }

        when (uri.host?.lowercase()) {
            "profile" -> {
                val userId = uri.pathSegments.getOrNull(0)
                if (!userId.isNullOrBlank()) {
                    launchProfile(context, userId)
                } else {
                    launchMain(context)
                }
            }
            "payment" -> {
                val action = uri.pathSegments.getOrNull(0)?.lowercase()
                if (action == "confirm") {
                    launchPaymentConfirm(context)
                } else {
                    launchMain(context)
                }
            }
            else -> launchMain(context)
        }
    }

    private fun isSupported(uri: Uri): Boolean {
        return uri.scheme?.lowercase() == SCHEME
    }

    private fun launchMain(context: Context) {
        val i = Intent(context, MainActivity::class.java).apply {
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(i)
    }

    private fun launchProfile(context: Context, userId: String) {
        val i = Intent(context, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_USER_ID, userId)
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(i)
    }

    private fun launchPaymentConfirm(context: Context) {
        val i = Intent(context, PaymentConfirmActivity::class.java).apply {
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(i)
    }
}

